INSERT INTO `pages` (`id`, `slug`, `title`, `hero_img`, `content`) VALUES
(1, 'mythology', 'Μυθολογια', 'athens.jpg', '<section class=\"hero-mythology\">\r\n        <div class=\"hero-overlay\">\r\n            <h1>ΕΛΛΗΝΙΚΗ ΜΥΘΟΛΟΓΙΑ</h1>\r\n            <p>Ένα ταξίδι στον κόσμο των Θεών και των Ηρώων</p>\r\n        </div>\r\n    </section><main class=\"container\">\r\n        <div class=\"myth-grid\">\r\n            \r\n            <div class=\"myth-card\">\r\n                <img src=\"images/διας.jpg\" alt=\"Δίας\">\r\n                <h3>Δίας</h3>\r\n                <p>Ο πατέρας των Θεών και άρχοντας του Ολύμπου.Ο Δίας είναι ο κυρίαρχος \r\n                    του Ολύμπου, ο θεός του ουρανού, της βροντής και της δικαιοσύνης. \r\n                    Αφού νίκησε τον πατέρα του, τον Κρόνο, και τους Τιτάνες, μοίρασε \r\n                    τον κόσμο με τα αδέρφια του και εγκαθίδρυσε την εξουσία των θεών, \r\n                    κρατώντας για τον εαυτό του το ισχυρότερο όπλο: τον κεραυνό.\r\n                    Ως θεός της φιλοξενίας και των όρκων, επέβλεπε τη ζωή των θνητών και την τάξη στο σύμπαν.\r\n                    Παρά την παντοδυναμία του, οι μύθοι του είναι γεμάτοι από τις περιπέτειές του στη γη, \r\n                    τις μεταμορφώσεις του και τις συγκρούσεις του με την Ήρα, αναδεικνύοντας την πολύπλευρη \r\n                    και συχνά ανθρώπινη φύση του.</p>\r\n            </div>\r\n\r\n            <div class=\"myth-card\">\r\n                <img src=\"images/αθηνά.jpg\" alt=\"Αθηνά\">\r\n                <h3>Αθηνά</h3>\r\n                <p>Η προστάτιδα του γάμου και βασίλισσα των Θεών.\r\n                    Η Αθηνά γεννήθηκε από το κεφάλι του Δία, πάνοπλη και πάμπλουτη σε σοφία. \r\n                    Είναι η προστάτιδα των τεχνών, της στρατηγικής και της πόλης των. \r\n                    Αντίθετα με τον Άρη, η Αθηνά αντιπροσωπεύει τη δίκαιη μάχη και τη λογική \r\n                    στον πόλεμο. Ήταν η πιστή σύμβουλος των μεγαλύτερων ηρώων, \r\n                    όπως ο Οδυσσέας και ο Περσέας, βοηθώντας τους να νικήσουν τα εμπόδια \r\n                    όχι μόνο με τη δύναμη, αλλά κυρίως με την οξυδέρκεια του μυαλού τους</p>\r\n            </div>\r\n\r\n            <div class=\"myth-card\">\r\n                <img src=\"images/Poseidon.jpg\" alt=\"Ποσειδώνας\">\r\n                <h3>Ποσειδώνας</h3>\r\n                <p>Ο κυρίαρχος των θαλασσών και των ωκεανών.Ο Ποσειδώνας κρατά \r\n                    την τρίαινα και κυβερνά τα βάθη των ωκεανών, τις λίμνες και τους ποταμούς.\r\n                     Είναι ο θεός που μπορεί να προκαλέσει τρομερές τρικυμίες \r\n                     αλλά και να ηρεμήσει τα νερά, ενώ θεωρείται υπεύθυνος για τους σεισμούς,\r\n                      τους οποίους προκαλούσε χτυπώντας τη γη με το όπλο του. \r\n                      Η προσωπικότητά του ήταν ορμητική και απρόβλεπτη όπως η θάλασσα. \r\n                      Έμεινε γνωστός για την έχθρα του με τον Οδυσσέα, τον οποίο \r\n                      καταδίωκε για χρόνια στα πέλαγα, αλλά και για τη δημιουργία \r\n                      του πρώτου αλόγου, αναδεικνύοντας τη σημασία του τόσο στη \r\n                      ναυτιλία όσο και στη στεριά.</p>\r\n            </div>\r\n\r\n            <div class=\"myth-card\">\r\n                <img src=\"images/ηρακλης.jpg\" alt=\"Ηρακλης\">\r\n                <h3>Ηρακλής</h3>\r\n                <p>Ο Αήττητος Ημίθεος.Ο Ηρακλής είναι ο δημοφιλέστερος ήρωας της αρχαιότητας,\r\n                     γιος του Δία και της Αλκμήνης. Για να εξιλεωθεί από τα δεινά που \r\n                     του προκάλεσε η Ήρα, υποχρεώθηκε να υπηρετήσει τον Ευρυσθέα και \r\n                     να φέρει εις πέρας τους δώδεκα άθλους, δοκιμασίες που ξεπερνούσαν \r\n                     κάθε ανθρώπινη αντοχή. Από τη λιονταρή της Νεμέας μέχρι τα μήλα \r\n                     των Εσπερίδων, ο Ηρακλής συμβολίζει τη δύναμη της θέλησης και την\r\n                      πάλη του ανθρώπου ενάντια στο πεπρωμένο. Μετά το θάνατό του, \r\n                      η αρετή του τον οδήγησε στον Όλυμπο, όπου έγινε ο μοναδικός \r\n                      ήρωας που έλαβε την αθανασία και έγινε θεός.</p>\r\n            </div>\r\n\r\n            <div class=\"myth-card\">\r\n                <img src=\"images/οδυσσεας.jpg\" alt=\"Οδυσσέας\">\r\n                <h3>Οδυσσέας</h3>\r\n                <p> Ο Πολυμήχανος Βασιλιάς\r\n                    Ο Οδυσσέας, ο βασιλιάς της Ιθάκης, έμεινε στην ιστορία ως το σύμβολο της ευφυΐας και \r\n                    της πολυμηχανίας. Ήταν ο εμπνευστής του Δούρειου Ίππου που χάρισε τη νίκη στους Έλληνες\r\n                    στην Τροία, όμως η μεγαλύτερη πρόκληση της ζωής του ήταν η \"Οδύσσεια\": το δεκαετές, \r\n                    περιπετειώδες ταξίδι της επιστροφής στην πατρίδα του. Αντιμετώπισε μυθικά τέρατα όπως\r\n                    ο Κύκλωπας Πολύφημος και η Σκύλλα, αντιστάθηκε στη γοητεία των Σειρήνων και στην οργή \r\n                    του Ποσειδώνα, βασιζόμενος πάντα στο κοφτερό του μυαλό. Η επιστροφή του στην Ιθάκη και \r\n                    η επανένωση με την Πηνελόπη συμβολίζουν τον αέναο αγώνα του ανθρώπου να ξεπεράσει κάθε \r\n                    εμπόδιο και να βρει τον δικό του προορισμό.</p>\r\n                                </div>\r\n\r\n            <div class=\"myth-card\">\r\n                <img src=\"images/περσεαςjpg.jpg\" alt=\"Περσέας\">\r\n                <h3>Περσέας</h3>\r\n                <p>Ο Φονιάς της ΜέδουσαςΟ Περσέας ξεκίνησε ένα ακατόρθωτο ταξίδι \r\n                    για να φέρει το κεφάλι της Μέδουσας, της γοργόνας που πέτρωνε \r\n                    όποιον την κοίταζε. Με τη βοήθεια των θεών, που του χάρισαν \r\n                    φτερωτά σανδάλια, μια μαγική περικεφαλαία και έναν καθρέφτη-ασπίδα, \r\n                    κατάφερε να νικήσει το τέρας. Στην επιστροφή του, έσωσε την Ανδρομέδα \r\n                    από το θαλάσσιο κήτος και ίδρυσε τις Μυκήνες, μια από τις σπουδαιότερες \r\n                    πόλεις της αρχαιότητας. Ο Περσέας θεωρείται ένας από τους πιο \"καθαρούς\"\r\n                     ήρωες, καθώς κατάφερε να θριαμβεύσει βασιζόμενος στη βοήθεια των θεών \r\n                     και στην απόλυτη ψυχραιμία του.</p>\r\n            </div>\r\n        </div>\r\n\r\n         <section class=\"mythology-section\">\r\n            <div class=\"mythology-card\">\r\n                <div class=\"card-image\">\r\n                    <img src=\"images/Arxaioi-Filosofoi.jpg\" alt=\"Αρχαίοι Φιλόσοφοι\">\r\n                </div>\r\n                <div class=\"card-text\">\r\n                    <h2>\"Η ΓΕΝΝΗΣΗ ΤΩΝ ΘΕΩΝ (ή Η ΚΟΣΜΟΓΟΝΙΑ)</h2>\r\n                    <p>\r\n                        Στην αρχή υπήρχε μόνο το Χάος. Μέσα από το απόλυτο σκοτάδι γεννήθηκε η Γαία, \r\n                        ο Έρωτας και ο Τάρταρος. Από την ένωση της Γαίας με τον Ουρανό γεννήθηκαν οι \r\n                        Τιτάνες, οι Κύκλωπες και οι Εκατόγχειρες, ξεκινώντας την αιώνια πάλη για την \r\n                        κυριαρχία του σύμπαντος.”  Η πτώση του Ουρανού από τον γιο του, τον Κρόνο, \r\n                        σηματοδότησε την εποχή των Τιτάνων, μια περίοδο γεμάτη φόβο και προφητείες. \r\n                    <p>\r\n                        Ο Κρόνος, φοβούμενος την ίδια του τη μοίρα, προσπάθησε να σταματήσει τον \r\n                        χρόνο καταπίνοντας τα παιδιά του, όμως η Ρέα κατάφερε να σώσει τον τελευταίο\r\n                         της γιο, τον Δία. Κρυμμένος στο Ιδαίο Άντρο της Κρήτης, \r\n                         ο μελλοντικός βασιλιάς των θεών μεγάλωσε προετοιμάζοντας την Τιτανομαχία, \r\n                         τη σύγκρουση που θα έθετε τέλος στο παλιό καθεστώς και θα έφερνε την τάξη\r\n                          στο σύμπαν μέσα από το φως του Ολύμπου.”\r\n                    </p>\r\n                </div>\r\n            </div>\r\n        </section>\r\n\r\n        <section class=\"myth-detailed-text\">\r\n    <h2>Η Σημασία των Μύθων στην Αρχαιότητα</h2>\r\n    <div class=\"text-content\">\r\n        <p>\r\n           Η Αρχή και η Κοσμογονία\r\n\r\n«Η ελληνική μυθολογία ξεκινά με το Χάος, μια κατάσταση απόλυτης αταξίας από την οποία \r\nαναδύθηκαν οι πρώτες δυνάμεις του σύμπαντος: η Γαία, ο Έρωτας και ο Τάρταρος. \r\nΗ ένωση της Γαίας με τον Ουρανό γέννησε τους Τιτάνες, τους Κύκλωπες και τους Εκατόγχειρες. \r\nΑυτή η αρχέγονη περίοδος χαρακτηρίζεται από την άγρια σύγκρουση μεταξύ των γενεών, \r\nη οποία κορυφώθηκε με την Τιτανομαχία. Η νίκη του Δία και των Ολύμπιων θεών σήμανε \r\nτην επιβολή της τάξης και της δικαιοσύνης πάνω στις ανεξέλεγκτες δυνάμεις της φύσης.»\r\nΗ Κυριαρχία του Ολύμπου«Με έδρα τον χιονισμένο Όλυμπο, οι δώδεκα θεοί καθόρισαν την \r\nτύχη των ανθρώπων και τη λειτουργία του κόσμου. Κάθε θεότητα ενσάρκωνε μια διαφορετική \r\nπτυχή της ανθρώπινης εμπειρίας: από τη σοφία της Αθηνάς και το φως του Απόλλωνα, \r\nμέχρι την ορμή του Άρη και τη δύναμη του Ποσειδώνα. \r\n        </p>\r\n        <p>\r\n           Οι θεοί των Ελλήνων δεν ήταν \r\nαπόμακροι, αλλά είχαν ανθρώπινα πάθη, αδυναμίες και συγκρούσεις, κάτι που έκανε τις \r\nιστορίες τους να παραμένουν ζωντανές και διδακτικές ανά τους αιώνες.»\r\nΗ Κληρονομιά των Ηρώων«Πέρα από τους θεούς, η μυθολογία είναι γεμάτη από ηρωικές μορφές\r\n που ξεπέρασαν τα ανθρώπινα όρια. Ο Ηρακλής με τους άθλους του, ο Οδυσσέας με την\r\n  πολυμήχανη φύση του και ο Προμηθέας που χάρισε τη φωτιά στους θνητούς, συμβολίζουν\r\n   τον διαρκή αγώνα του ανθρώπου ενάντια στο πεπρωμένο και το άγνωστο. Αυτές οι \r\n   αφηγήσεις δεν είναι απλώς παραμύθια, αλλά οι ρίζες του δυτικού πολιτισμού, \r\n   επηρεάζοντας την τέχνη, τη φιλοσοφία και την ψυχολογία μέχρι και σήμερα.»\r\n        </p>\r\n        </div>\r\n</section>\r\n\r\n    </main>\r\n'),
(2, 'filosofoi', 'φιλοσοφοι', '', '\r\n    <section class=\"hero-philosophers\">\r\n        <div class=\"hero-overlay\">\r\n            <h1>ΑΡΧΑΙΟΙ ΦΙΛΟΣΟΦΟΙ</h1>\r\n            <p>\"Ο ανεξέταστος βίος ου βιωτός ανθρώπω\"</p>\r\n        </div>\r\n    </section>\r\n\r\n    <main class=\"container\">\r\n        \r\n        <section class=\"philosopher-entry\">\r\n            <div class=\"philo-image\">\r\n                <img src=\"images/Socrates.jpg\" alt=\"Σωκράτης\">\r\n            </div>\r\n            <div class=\"philo-text\">\r\n                <h2>Σωκράτης</h2>\r\n                <p>Ο Σωκράτης (Αλωπεκή, Αρχαία Αθήνα, 470 π.Χ./469 – Αρχαία Αθήνα, 399 π.Χ.)\r\n                    [1] ήταν Έλληνας Αθηναίος φιλόσοφος, που θεωρείται ο ιδρυτής της\r\n                     Δυτικής φιλοσοφίας και συγκαταλέγεται στους πρώτους ηθικούς φιλοσόφους.\r\n                      Δεν συνέγραψε κάποιο φιλοσοφικό έργο όσο ζούσε· \r\n                      η διδασκαλία του επιβίωσε μέσω των καταγραφών που έκαναν μαθητές του \r\n                      όπως ο Πλάτων και ο Ξενοφών, μετά τον θάνατό του.\r\n                       Οι καταγραφές αυτές συνιστούν διαλόγους, στους οποίους ο Σωκράτης \r\n                       και οι συνδιαλεγόμενοι με αυτόν εξετάζουν διάφορα ζητήματα βάσει \r\n                       ης διαλεκτικής μεθόδου. Συχνά, οι γραπτές μαρτυρίες της φιλοσοφίας \r\n                       του παρουσιάζουν αντιφάσεις μεταξύ τους, με αποτέλεσμα η πλήρης \r\n                       ανακατασκευή της σωκρατικής σκέψης να συνιστά δυσεπίλυτο πρόβλημα.\r\n                </p>\r\n            </div>\r\n        </section>\r\n\r\n        <section class=\"philosopher-entry reverse\">\r\n            <div class=\"philo-image\">\r\n                <img src=\"images/πλάτωνας-01.jpg\" alt=\"Πλάτων\">\r\n            </div>\r\n            <div class=\"philo-text\">\r\n                <h2>Πλάτων</h2>\r\n                <p>Ο Πλάτων (Αρχαία Αθήνα, 428/9 π.Χ. – Αρχαία Αθήνα, 347 π.Χ.) \r\n                    ήταν αρχαίος Έλληνας φιλόσοφος από την Αθήνα, ο πιο γνωστός μαθητής \r\n                    του Σωκράτη και δάσκαλος του Αριστοτέλη. Το έργο του, που με τη μορφή \r\n                    φιλοσοφικών διαλόγων έχει διασωθεί ολόκληρο (του αποδίδονται ακόμα και \r\n                    μερικά νόθα έργα), άσκησε τεράστια επιρροή στην αρχαία ελληνική \r\n                    φιλοσοφία και γενικότερα στη δυτική φιλοσοφική παράδοση μέχρι και σήμερα</p>\r\n            </div>\r\n        </section>\r\n\r\n         <section class=\"philosopher-entry\">\r\n            <div class=\"philo-image\">\r\n                <img src=\"images/αριστοτελης.jpg\" alt=\"Σωκράτης\">\r\n            </div>\r\n            <div class=\"philo-text\">\r\n                <h2>Αριστοτελης</h2>\r\n                <p>Ο Αριστοτέλης (Αρχαία Στάγειρα, 384 π.Χ. - Αρχαία Χαλκίδα, 322 π.Χ.) \r\n                    ήταν αρχαίος Έλληνας φιλόσοφος και επιστήμονας που γεννήθηκε στα\r\n                     Στάγειρα της Χαλκιδικής, στη Μακεδονία. Σε ηλικία 17 ετών εισέρχεται \r\n                     στην Ακαδημία του Πλάτωνα, στην Αθήνα, όπου παραμένει έως τα 37 του έτη.\r\n                      Εκεί συνδέεται τόσο με τον ίδιο τον Πλάτωνα όσο και με τον Εύδοξο, \r\n                      τον Ξενοκράτη και άλλους στοχαστές.[1] Τα έργα του αναφέρονται σε \r\n                      πολλές επιστήμες, όπως φυσική, βιολογία, ζωολογία, μεταφυσική, \r\n                      λογική, ηθική, ποίηση, θέατρο, μουσική, ρητορική, πολιτική κ.ά, \r\n                      και συνιστούν το πρώτο ολοκληρωμένο σύστημα στη δυτική φιλοσοφία.\r\n            </div>\r\n        </section>\r\n\r\n        <section class=\"philosophy-quotes\">\r\n    <div class=\"container\">\r\n        <h2>Σοφά Λόγια</h2>\r\n        <div class=\"quotes-grid\">\r\n            <div class=\"quote-card\">\r\n                <p>\"Γνώθι σαυτόν.\"</p>\r\n                <span>- Χίλων ο Λακεδαιμόνιος</span>\r\n            </div>\r\n            <div class=\"quote-card\">\r\n                <p>\"Η παιδεία είναι δεύτερος ήλιος για τους ανθρώπους.\"</p>\r\n                <span>- Πλάτων</span>\r\n            </div>\r\n            <div class=\"quote-card\">\r\n                <p>\"Εν οίδα, ότι ουδέν οίδα.\"</p>\r\n                <span>- Σωκράτης</span>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</section>\r\n\r\n<section class=\"philosophy-epilogue container\">\r\n    <div class=\"epilogue-content\">\r\n        <h2>Η Κληρονομιά της Αρχαίας Σκέψης</h2>\r\n        <p>\r\n            Η αρχαία ελληνική φιλοσοφία δεν αποτελεί απλώς ένα ιστορικό κεφάλαιο του παρελθόντος, \r\n            αλλά το θεμέλιο πάνω στο οποίο οικοδομήθηκε ο σύγχρονος δυτικός πολιτισμός. \r\n            Από την ηθική του Σωκράτη και την πολιτική σκέψη του Πλάτωνα, μέχρι την επιστημονική \r\n            μεθοδολογία του Αριστοτέλη, οι ερωτήσεις που έθεσαν οι αρχαίοι στοχαστές παραμένουν \r\n            επίκαιρες μέχρι σήμερα.\r\n        </p>\r\n        <p>\r\n            Μελετώντας τους φιλοσόφους, δεν μαθαίνουμε απλώς τι σκέφτηκαν κάποιοι άνθρωποι πριν από \r\n            χιλιάδες χρόνια, αλλά ανακαλύπτουμε εργαλεία για να σκεφτόμαστε κριτικά, να αμφισβητούμε \r\n            το προφανές και να αναζητούμε την αλήθεια στην καθημερινότητά μας.\r\n        </p>\r\n    </div>\r\n</section>'),
(5, 'olympics', 'ολυμπιακοι αγωνες', '', ' <section class=\"hero-olympics\">\r\n        <div class=\"hero-overlay\">\r\n            <h1>ΟΛΥΜΠΙΑΚΟΙ ΑΓΩΝΕΣ</h1>\r\n            <p>Το πνεύμα του ευ αγωνίζεσθαι γεννήθηκε εδώ</p>\r\n        </div>\r\n    </section>\r\n\r\n    <main class=\"container\">\r\n        \r\n        <section class=\"olympics-intro\">\r\n            <h2>Η Γέννηση στην Ολυμπία</h2>\r\n            <p>Από το 776 π.Χ., οι Αγώνες ήταν το πιο σημαντικό γεγονός του αρχαίου κόσμου. Πραγματοποιούνταν κάθε τέσσερα χρόνια προς τιμήν του Δία, φέρνοντας κοντά όλους τους Έλληνες.</p>\r\n        </section>\r\n<div class=\"sports-grid\">\r\n    <div class=\"sport-card\">\r\n        <img src=\"images/δρομος.jpg\" alt=\"Δρόμος\">\r\n        <div class=\"sport-content\">\r\n            <h3>Δρόμος</h3>\r\n            <p>Το \"στάδιον\" ήταν το αρχαιότερο και πιο τιμημένο αγώνισμα των αγώνων.</p>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"sport-card\">\r\n        <img src=\"images/παλη.jpg\" alt=\"Πάλη\">\r\n        <div class=\"sport-content\">\r\n            <h3>Πάλη</h3>\r\n            <p>Ένα άθλημα δύναμης και τεχνικής που απαιτούσε απόλυτη πειθαρχία.</p>\r\n        </div>\r\n    </div>\r\n\r\n    <div class=\"sport-card\">\r\n        <img src=\"images/αρματοδρομιες.jpg\" alt=\"Αρματοδρομίες\">\r\n        <div class=\"sport-content\">\r\n            <h3>Αρματοδρομίες</h3>\r\n            <p>Το πιο θεαματικό και επικίνδυνο αγώνισμα που γινόταν στον Ιππόδρομο.</p>\r\n        </div>\r\n    </div>\r\n</div>\r\n\r\n        <section class=\"truce-section\">\r\n            <div class=\"truce-content\">\r\n                <h2>Η Ιερή Εκεχειρία</h2>\r\n                <p>Κατά τη διάρκεια των Αγώνων, όλοι οι πόλεμοι σταματούσαν. \r\n                    Ήταν μια περίοδος ειρήνης όπου η αριστεία του πνεύματος και του σώματος \r\n                    είχε τον πρώτο λόγο.Η λέξη Εκεχειρία σημαίνει κυριολεκτικά «έχω \r\n                    τις χείρες μακριά \r\n                    από τα όπλα». Πριν την έναρξη των Αγώνων, τρεις αγγελιοφόροι \r\n                    (οι σπονδοφόροι)\r\n                     έφευγαν από την Ήλιδα στεφανωμένοι με κλαδιά ελιάς και \r\n                     ταξίδευαν σε όλο τον \r\n                     ελληνικό κόσμο για να ανακοινώσουν την εκεχειρία.\r\n                    Για τρεις μήνες, κάθε εχθροπραξία σταματούσε. Ο σκοπός ήταν διπλός: \r\n                    να μπορέσουν οι αθλητές και οι θεατές να ταξιδέψουν με ασφάλεια προς \r\n                    την Ολυμπία, αλλά και να υπενθυμίσει σε όλες τις πόλεις-κράτη ότι η \r\n                    κοινή τους καταγωγή και ο πολιτισμός ήταν πιο σημαντικά από τις πολιτικές\r\n                     τους διαφορές.\r\n                     Όποια πόλη παραβίαζε την εκεχειρία, αποκλειόταν από τους Αγώνες και της \r\n                     επιβαλλόταν βαρύ πρόστιμο, καθώς η πράξη αυτή θεωρούνταν ύβρις προς \r\n                     τον ίδιο τον Δία.\"</p>\r\n            </div>\r\n        </section>'),
(6, 'athens', 'αρχαια αθηνα', '<section class=\"hero-olympics\">\r\n        <div class=\"hero-overlay\">\r\n            <h1>ΟΛΥΜΠΙΑΚΟΙ ΑΓΩΝ', ' <section class=\"hero-athens\">\r\n        <div class=\"hero-overlay\">\r\n            <h1>ΑΘΗΝΑ</h1>\r\n            <p>Η κοιτίδα της Δημοκρατίας και του Πολιτισμού</p>\r\n        </div>\r\n    </section>\r\n\r\n    <main class=\"container\">\r\n        \r\n        <section class=\"athens-intro\">\r\n            <div class=\"intro-grid\">\r\n                <div class=\"intro-text\">\r\n                    <h2>Ο Χρυσός Αιώνας</h2>\r\n                    <p>Υπό την ηγεσία του Περικλή, η Αθήνα έφτασε στο απόγειο της δόξας της. Εδώ γεννήθηκε η Δημοκρατία, το θέατρο και οι τέχνες που θα καθόριζαν την πορεία της ανθρωπότητας.</p>\r\n                </div>\r\n                <div class=\"intro-image\">\r\n                    <img src=\"images/ακροπολη.jpg\" alt=\"ακροπολη\">\r\n                </div>\r\n            </div>\r\n        </section>\r\n\r\n        <section class=\"athens-monuments\">\r\n            <h2>Τα Μνημεία της Πόλης</h2>\r\n            <div class=\"monuments-gallery\">\r\n                <div class=\"monument-item\">\r\n                    <img src=\"images/παρθενωνας.jpg\" alt=\"Παρθενώνας\">\r\n                    <div class=\"monument-info\"><h3>Παρθενώνας</h3></div>\r\n                </div>\r\n                <div class=\"monument-item\">\r\n                    <img src=\"images/θεατρο διονυσου.jpg\" alt=\"Θέατρο Διονύσου\">\r\n                    <div class=\"monument-info\"><h3>Θέατρο Διονύσου</h3></div>\r\n                </div>\r\n                <div class=\"monument-item\">\r\n                    <img src=\"images/ναος ηφαιστου.jpg\" alt=\"Ναός Ηφαίστου\">\r\n                    <div class=\"monument-info\"><h3>Ναός Ηφαίστου</h3></div>\r\n                </div>\r\n            </div>\r\n        </section>\r\n\r\n        <section class=\"athens-info container\">\r\n    <h2>Πληροφορίες Επίσκεψης</h2>\r\n    <table class=\"info-table\">\r\n        <thead>\r\n            <tr>\r\n                <th>Μνημείο</th>\r\n                <th>Τοποθεσία</th>\r\n                <th>Σημασία</th>\r\n            </tr>\r\n        </thead>\r\n        <tbody>\r\n            <tr>\r\n                <td>Παρθενώνας</td>\r\n                <td>Ακρόπολη</td>\r\n                <td>Ναός αφιερωμένος στην Αθηνά</td>\r\n            </tr>\r\n            <tr>\r\n                <td>Αρχαία Αγορά</td>\r\n                <td>Θησείο</td>\r\n                <td>Κέντρο εμπορίου και δημοκρατίας</td>\r\n            </tr>\r\n            <tr>\r\n                <td>Ωδείο Ηρώδου Αττικού</td>\r\n                <td>Νότια Κλιτύς</td>\r\n                <td>Ρωμαϊκό θέατρο (χρησιμοποιείται ακόμα)</td>\r\n            </tr>\r\n        </tbody>\r\n    </table>\r\n</section>\r\n');

